b'import pytest\nfrom converters import celsius_to_fahrenheit, fahrenheit_to_celsius, celsius_to_kelvin\n\ndef test_celsius_to_fahrenheit():\n    assert celsius_to_fahrenheit(0) == 32\n    assert celsius_to_fahrenheit(100) == 212\n    assert celsius_to_fahrenheit(-40) == -40\n    assert celsius_to_fahrenheit(1.5) == 34.7\n    with pytest.raises(TypeError):\n        celsius_to_fahrenheit(True)\n    with pytest.raises(TypeError):\n        celsius_to_fahrenheit("string")\n    with pytest.raises(TypeError):\n        celsius_to_fahrenheit(None)\n\ndef test_fahrenheit_to_celsius():\n    assert fahrenheit_to_celsius(32) == 0\n    assert fahrenheit_to_celsius(212) == 100\n    assert fahrenheit_to_celsius(-40) == -40\n    assert fahrenheit_to_celsius(34.7) == 1.5\n    with pytest.raises(TypeError):\n        fahrenheit_to_celsius(True)\n    with pytest.raises(TypeError):\n        fahrenheit_to_celsius("string")\n    with pytest.raises(TypeError):\n        fahrenheit_to_celsius(None)\n\ndef test_celsius_to_kelvin():\n    assert celsius_to_kelvin(0) == 273.15\n    assert celsius_to_kelvin(100) == 373.15\n    assert celsius_to_kelvin(-273.15) == 0\n    assert celsius_to_kelvin(-273.14) == 0.01\n    with pytest.raises(TypeError):\n        celsius_to_kelvin(True)\n    with pytest.raises(TypeError):\n        celsius_to_kelvin("string")\n    with pytest.raises(TypeError):\n        celsius_to_kelvin(None)'